import{C as e,o as n,c as o,a5 as a,E as l}from"./chunks/framework.CW28V7p_.js";const k=JSON.parse('{"title":"2. Slots, epochs, time на Solana","description":"","frontmatter":{},"headers":[],"relativePath":"module-1/2-slots-epochs.md","filePath":"module-1/2-slots-epochs.md","lastUpdated":1780937944000}'),h={name:"module-1/2-slots-epochs.md"},c=Object.assign(h,{setup(r){const t={id:"m1-2-slots-epochs",title:"🧠 Mini-check: Slots, epochs, time",intro:"3 питання — фундаментальна Solana terminology про час.",questions:[{type:"mcq",q:"Що з цього правильне про slot на Solana? (обери всі)",options:["Slot це 400ms window під час якого один (заздалегідь обраний) leader може створити block","Один slot завжди містить рівно один block","Якщо leader не зміг створити block у своєму slot — slot вважається skipped","Slot number монотонно росте, не починається з нуля для кожного epoch"],correct:[0,2,3],explanation:"Slot це time window для leader. Block може бути створений (success) або skipped (leader fail). #2 неправильно: slot може бути empty. Slot numbering глобальне, не resetиться кожен epoch."},{type:"command",q:"Як подивитись інфо про поточний epoch (slot range, progress, скільки часу залишилось)? Напиши команду.",accepts:["solana epoch-info","solana epoch-info --url mainnet-beta","solana epoch-info --url http://localhost:8899"],ideal:"solana epoch-info",explanation:"solana epoch-info показує: Epoch number, Slot Range (start..end), Epoch Completed Percent, Epoch Completed Time. Це найкорисніша одно-командна довідка про де знаходимось у часі."},{type:"scenario",q:'На mainnet тобі сказали "почекай 1 epoch перш ніж stake активний". Поясни що це означає у часовому вимірі — скільки часу чекати, чому саме 1 epoch, що відбудеться в кінці.',ideal:`Один epoch на mainnet = ~2 дні (~432000 slots × 400ms = 172800 сек = 48 годин).

Чому 1 epoch: stake delegation активується ТІЛЬКИ на boundary епохи. Якщо ти delegateиш на slot середини epoch N — твій stake додається у "activating" state, чекає кінця epoch N, і стає active на старті epoch N+1.

Це механіка warmup. Solana має це обмеження щоб уникнути в межах epoch фрагментації stake (consensus працює з єдиним stake snapshot per epoch).

Що відбудеться в кінці: на slot 0 наступного epoch твій stake потрапляє в active set, validator починає включати твою stake вагу у голосуванні, ти починаєш заробляти rewards (якщо validator voteить).`,explanation:"Ключове: epoch boundaries це consensus moment коли stake snapshots оновлюються. Якщо описала ~2 дні + чому boundary важлива — повна відповідь."}]};return(p,s)=>{const i=e("Quiz");return n(),o("div",null,[s[0]||(s[0]=a("",71)),l(i,{data:t}),s[1]||(s[1]=a("",6))])}}});export{k as __pageData,c as default};
